namespace sv_42b7584e2bd2405e95da8b2ada3c23b1.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    public static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    public Product Clone() => (Product)MemberwiseClone();
}

using sv_42b7584e2bd2405e95da8b2ada3c23b1.Models;

namespace sv_42b7584e2bd2405e95da8b2ada3c23b1.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "USB-C Cable", Quantity = 300, UnitPrice = 9.99m, Category = "Electronics" },
        new Product { Id = 3, Name = "Cotton T-Shirt", Quantity = 200, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 4, Name = "Running Shoes", Quantity = 75, UnitPrice = 89.99m, Category = "Clothing" },
        new Product { Id = 5, Name = "Organic Coffee Beans", Quantity = 500, UnitPrice = 12.00m, Category = "Food" },
        new Product { Id = 6, Name = "Notebook Journal", Quantity = 120, UnitPrice = 6.50m, Category = "Other" },
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => p.Clone()).ToList());
        }
    }

    public Task UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var index = _products.FindIndex(p => p.Id == updated.Id);
