@page "/inventory"
@rendermode InteractiveServer
@using sv_42b7584e2bd2405e95da8b2ada3c23b1.Models
@using sv_42b7584e2bd2405e95da8b2ada3c23b1.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProduct is not null && _editingProduct.Id == product.Id)
                {
                    <tr>
                        <td>
                            <input class="form-control" @bind="_editingProduct.Name" />
                            @if (_validationErrors.ContainsKey(nameof(Product.Name)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Name)]</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editingProduct.Quantity" />
                            @if (_validationErrors.ContainsKey(nameof(Product.Quantity)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Quantity)]</div>
                            }
                        </td>
                        <td>
                            <input type="number" step="0.01" class="form-control" @bind="_editingProduct.UnitPrice" />
                            @if (_validationErrors.ContainsKey(nameof(Product.UnitPrice)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.UnitPrice)]</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editingProduct.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Product.Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (_validationErrors.ContainsKey(nameof(Product.Category)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Category)]</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private Product? _editingProduct;
    private Dictionary<string, string> _validationErrors = new();

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        _validationErrors.Clear();
        _editingProduct = product.Clone();
    }

    private void Cancel()
    {
        _editingProduct = null;
        _validationErrors.Clear();
    }

    private async Task SaveAsync()
    {
        if (_editingProduct is null) return;

        _validationErrors.Clear();

        var ctx = new ValidationContext(_editingProduct);
        var results = new List<ValidationResult>();
        if (!Validator.TryValidateObject(_editingProduct, ctx, results, validateAllProperties: true))
        {
            foreach (var r in results)
            {
                foreach (var member in r.MemberNames)
                {
                    _validationErrors.TryAdd(member, r.ErrorMessage ?? "Invalid value.");
                }
            }
            return;
        }

        await InventoryService.UpdateAsync(_editingProduct);
        _products = await InventoryService.GetAllAsync();
        _editingProduct = null;
    }
}

